import{_ as e,o as a,c as r,ag as i}from"./chunks/framework.C9sp7nFj.js";const c=JSON.parse('{"title":"Memoh 中文文档","description":"","frontmatter":{},"headers":[],"relativePath":"zh/index.md","filePath":"zh/index.md","lastUpdated":1777012567000}'),o={name:"zh/index.md"};function s(h,t,l,n,m,d){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="memoh-中文文档" tabindex="-1">Memoh 中文文档 <a class="header-anchor" href="#memoh-中文文档" aria-label="Permalink to &quot;Memoh 中文文档&quot;">​</a></h1><p>Memoh（读作 /ˈmemoʊ/）是面向多角色、长记忆、容器化场景的 AI 智能体平台。你可以创建多个机器人，为每个机器人准备独立工作区与长期记忆，并通过 Telegram、Discord、飞书、QQ、Matrix、Misskey、钉钉、企微、微信、公众号、邮件或内置网页端接入。</p><h2 id="起步" tabindex="-1">起步 <a class="header-anchor" href="#起步" aria-label="Permalink to &quot;起步&quot;">​</a></h2><ul><li><strong><a href="/zh/about.html">产品概览</a></strong>：平台在做什么、和其它方案差别在哪。</li><li><strong><a href="/zh/installation/docker.html">Docker 安装</a></strong>：推荐的一键/Compose 部署方式。</li><li><strong><a href="/zh/getting-started/provider-and-model.html">供应商与模型</a></strong>：配置上游 API、模型类型与能力标记。</li><li><strong><a href="/zh/getting-started/bot.html">机器人</a></strong>：创建机器人并配置各标签页。</li><li><strong><a href="/zh/getting-started/sessions.html">会话</a></strong>：聊天与 Discuss 模式、状态区、路由。</li><li><strong><a href="/zh/getting-started/slash-commands.html">斜杠命令</a></strong>：命令结构、权限与速查表。</li></ul><h2 id="功能指南" tabindex="-1">功能指南 <a class="header-anchor" href="#功能指南" aria-label="Permalink to &quot;功能指南&quot;">​</a></h2><ul><li><strong><a href="/zh/channels/index.html">渠道总览</a></strong>：支持的平台与各平台分篇（Telegram、飞书、企微、微信等）。</li><li><strong><a href="/zh/getting-started/access.html">访问控制</a></strong>：ACL 预设、规则顺序与按来源限定。</li><li><strong><a href="/zh/getting-started/skills.html">技能</a></strong>：托管/发现、生效/被遮蔽、从超市安装。</li><li><strong><a href="/zh/getting-started/supermarket.html">超市</a></strong>：技能与 MCP 模板安装。</li><li><strong><a href="/zh/getting-started/mcp.html">MCP</a></strong>：Stdio/远程、OAuth、探测与导入导出。</li><li><strong><a href="/zh/getting-started/memory.html">长期记忆</a></strong>：记忆提供方与在界面里的操作。</li><li><strong><a href="/zh/getting-started/compaction.html">会话上下文压缩</a></strong>：缩小当前会话占用，不动存储里的长期记忆。</li></ul><p>其它「入门」子页已翻译：容器、文件、浏览器、心跳、计划任务、搜索、邮件、Supermarket 等，见下栏 <strong>入门（中文）</strong>。</p><h2 id="记忆与语音提供方" tabindex="-1">记忆与语音提供方 <a class="header-anchor" href="#记忆与语音提供方" aria-label="Permalink to &quot;记忆与语音提供方&quot;">​</a></h2><ul><li><a href="/zh/memory-providers/index.html">记忆提供方总览</a> · <a href="/zh/memory-providers/builtin.html">内置</a> · <a href="/zh/memory-providers/mem0.html">Mem0</a> · <a href="/zh/memory-providers/openviking.html">OpenViking</a></li><li><a href="/zh/tts-providers/index.html">TTS 总览</a> · <a href="/zh/tts-providers/edge.html">Edge TTS</a></li></ul><p>各页链接以本中文站路径为主；个别尚未翻译的英文页仍可从英文站侧栏进入。</p>',10)])])}const p=e(o,[["render",s]]);export{c as __pageData,p as default};
